// Build a Sentry-compatible event payload from the n8n error.
// The errored execution's full payload is on $input.first().json.
//
// We send to GlitchTip's /api/<project_id>/store/ which speaks Sentry
// protocol (n8n native Sentry node is half-baked; HTTP node is robust).

const err = $input.first().json;
const execution = err.execution || {};
const lastNode = execution.lastNodeExecuted || 'unknown_node';
const workflow = err.workflow || {};
const errorMsg = (execution.error && execution.error.message) || 'n8n workflow error';
const errorStack = (execution.error && execution.error.stack) || null;

// Try to surface clinic_id when present in any node's first item.
let clinicId = null;
try {
  const runData = execution.data && execution.data.resultData && execution.data.resultData.runData;
  if (runData) {
    for (const nodeName of Object.keys(runData)) {
      const runs = runData[nodeName] || [];
      const firstItem = runs[0] && runs[0].data && runs[0].data.main && runs[0].data.main[0] && runs[0].data.main[0][0];
      const json = firstItem && firstItem.json;
      if (json && (json.clinic_id || (json.body && json.body.clinic_id))) {
        clinicId = json.clinic_id || json.body.clinic_id;
        break;
      }
    }
  }
} catch (_) {}

const event = {
  event_id: crypto.randomUUID().replace(/-/g, ''),
  timestamp: new Date().toISOString(),
  platform: 'other',
  level: 'error',
  logger: 'n8n',
  server_name: 'n8n.easyscale.co',
  message: errorMsg,
  exception: {
    values: [
      {
        type: (execution.error && execution.error.name) || 'WorkflowError',
        value: errorMsg,
        stacktrace: errorStack ? { frames: [{ filename: 'n8n', context_line: errorStack }] } : undefined,
      },
    ],
  },
  tags: {
    service: 'n8n',
    workflow: workflow.name || 'unknown',
    node: lastNode,
    clinic_id: clinicId || 'unknown',
  },
  extra: {
    workflow_id: workflow.id,
    execution_id: execution.id,
    execution_url: execution.url,
  },
};

return [{ json: event }];
